struct DSU {
    parent: Vec<usize>,
    rank: Vec<usize>,
    count: usize,
}

impl DSU {
    fn new(n: usize) -> Self {
        let parent = (0..n).map(|i| i).collect::<Vec<_>>();
        let rank = vec![0; n];
        DSU { parent, rank, count: n }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) -> bool {
        let xroot = self.find(x);
        let yroot = self.find(y);
        if xroot == yroot {
            return false;
        }
        if self.rank[xroot] < self.rank[yroot] {
            self.parent[xroot] = yroot;
        } else {
            self.parent[yroot] = xroot;
            if self.rank[xroot] == self.rank[yroot] {
                self.rank[xroot] += 1;
            }
        }
        self.count -= 1;
        true
    }

    fn get_components(&self) -> usize {
        self.count
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    if edges.is_empty() {
        return 0;
    }
    let mut sorted_edges = edges;
    sorted_edges.sort_by(|a, b| a[2].cmp(&b[2]));
    let max_w = sorted_edges.last().unwrap()[2];
    let mut low = 0;
    let mut high = max_w;
    let mut answer = max_w;
    while low <= high {
        let mid = (low + high) / 2;
        let mut dsu = DSU::new(n);
        for edge in &sorted_edges {
            let w = edge[2];
            if w <= mid {
                let u = edge[0] as usize;
                let v = edge[1] as usize;
                dsu.union(u, v);
            }
        }
        let components = dsu.get_components();
        if components <= k {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    answer as i64
}
```

