            let v = edge[1] as usize;
            let w = edge[2];
            if w <= mid {
                dsu.union(u, v);
            }
        }
        let components = dsu.get_components();
        if components <= k {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    answer
}
