    let answer = maxW;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const dsu = new DSU(n);
        for (const [u, v, w] of edges) {
            if (w <= mid) {
                dsu.union(u, v);
            }
        }
        const components = dsu.getComponents();
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
